  ('safety', 1738, 'כשאתה מתקרב לרכב המוריד ילדים:', 'רד לשול ועבור את הרכב מימינו.', 'עליך לעוקפו במהירות כדי להקטין את הסכנה.', 'עליך לצפור ולעקוף את הרכב משמאלו.', 'האט את נסיעתך, סע במהירות סבירה והיכון לאפשרות עצירה.', 'd', '', ARRAY['C1','C','D','A','1','В']),
  ('traffic-laws', 10, 'מהי "דרך" על פי החוק?', 'כל מסילה, דרך, רחוב, סמטה, כיכר, מעבר, גשר או מקום פתוח שיש לציבור זכות לעבור בהם.', 'רק כבישים הסלולים באספלט או בבטון.', 'המונח "דרך" אינו מוגדר בחוק.', 'כל מקום שיש זכות לציבור לעבור בו, למעט רחובות עירוניים.', 'a', '', ARRAY['C1','C','D','A','1','В']),
  ('traffic-laws', 197, 'האם מותר לעצור, להעמיד או להחנות רכב בדרך מהירה?', 'מותר, בתנאי שיש שול רחב דיו.', 'אסור, פרט לרכב ציבורי.', 'אסור, פרט לרכב דו-גלגלי.', 'אסור, אלא אם כן סומן אחרת במפורש.', 'd', '/questions/3147.jpg', ARRAY['C1','C','D','A','В']),
  ('traffic-laws', 138, 'מהו הרווח המינימלי שעליך לשמור בינך ובין הרכב הנע לפניך, על פי החוק?', 'מרחק נסיעה של שתי שניות לפחות.', 'מרחק נסיעה של לפחות שלוש שניות (בשיטת 21...22...23).', 'מרחק נסיעה של שנייה אחת לפחות.', 'לפחות 22 מטרים.', 'c', '/questions/3138.jpg', ARRAY['C1','C','D','A','1','В']),
  ('traffic-laws', 1757, 'בקטע כביש דו-סטרי בעל נתיב אחד לכל כיוון שבין הנתיבים מפריד קו הפרדה רצוף:', 'אין הגבלה על עצירה וחנייה, אלא אם כן מוצב תמרור מתאים.', 'העצירה והחנייה אסורות אף בשול הדרך.', 'העצירה מותרת לאוטובוסים בלבד.', 'העצירה והחנייה מותרות רק במקביל למדרכה.', 'b', '', ARRAY['C1','C','D','A','1','В']),
  ('traffic-laws', 353, 'האם יש חובה להתקין סלי אשפה ברכב נוסעים פרטי?', 'לא. חובה להתקין סל אשפה רק ברכב ציבורי.', 'לא, אין חובה כזו.', 'כן. חובה להתקין סל אשפה מסוג שאישרה רשות הרישוי.', 'כן. חובה להתקין סל אשפה רק ברכב מסחרי.', 'c', '', ARRAY['C1','В']),
  ('signs', 476, 'כיצד תנהג על פי התמרור?', 'תן זכות קדימה לכלי רכב ולהולכי רגל.', 'עבור במהירות את קטע הדרך.', 'האט וגלה זהירות רבה. היכון לאפשרות של צורך בבלימת פתע.', 'האט ושלב להילוך סרק (ניוטרל).', 'c', '/questions/3475.jpg', ARRAY['C1','C','D','A','1','В']),
  ('traffic-laws', 1752, 'בכביש צר, כששני כלי רכב הבאים מכיוונים נגדיים אינם יכולים לעבור בעת ובעונה אחת:', 'יש זכות קדימה לרכב המהיר.', 'יש זכות קדימה למי שמגיע ראשון.', 'יש זכות קדימה לרכב המסיע יותר משמונה נוסעים.', 'שני כלי הרכב חייבים לסטות ימינה ככל האפשר ואף לרדת לשוליים.', 'd', '', ARRAY['C1','C','D','A','1','В']),
  ('signs', 1022, 'מה פירוש התמרור?', 'תמרור של מסר מחייב שלגביו אין תמרור בלוח התמרורים.', 'תמרור מודיעין בצורת מרובע.', 'תמרור לאזהרה, להוריה או לאיסור, המיועד לרכב ציבורי בלבד.', 'שלט המשמש לכל מיני מסרים לא מחייבים.', 'a', '/questions/31022.jpg', ARRAY['C1','C','D','A','1','В']),
  ('traffic-laws', 1356, 'פנסי החזית ברכב יאירו את הדרך באור:', 'בצבע אחיד, לבן או צהוב בהיר.', 'בצבע אחיד, אדום או צהוב בהיר.', 'בצבע אחיד, כחול או צהוב בהיר.', 'לבן או צהוב בהיר, לאו דווקא בצבע אחיד.', 'a', '', ARRAY['C1','C','D','A','1','В']),
  ('safety', 851, 'מה הן הבעיות המיוחדות העומדות לפני נהג הרכב בלילה?', 'שדה (טווח) ראייה מוגבל, סינוור, אומדני מרחק לא נכונים.', 'תפקוד לקוי של הנהג עקב תאורה מחוץ לרכב.', 'ריבוי כלי רכב בסביבתו בשעות הלילה.', 'ירידה בהספק (כוח) המנוע עקב הפעלת מערכת התאורה.', 'a', '', ARRAY['C1','C','D','A','1','В']),
  ('signs', 682, 'מה פירוש הסימון השחור-לבן ליד הכביש?', 'מקום חנייה מוסדרת על ידי הרשות המקומית.', 'הסימון מיועד להדגשת הימצאותם של מדרכות ושל איי תנועה בנויים בסמוך לכביש.', 'מקום עצירה וחנייה לפני מפגש מסילת ברזל.', 'כל עצירה או חנייה אסורות.', 'b', '/questions/3682.jpg', ARRAY['C1','C','D','A','1','В']),
