  ('traffic-laws', 1758, 'כיצד צריך לפעול נהג רכב המתקרב לבתי ספר ולמגרשי משחקים?', 'יאט את הנסיעה ויגביר את הערנות.', 'יימנע מלהיכנס אל הרחוב, פרט לשעות הלילה.', 'יצפור כל הזמן כדי להזהיר את הילדים שלא יקפצו לכביש.', 'ימשיך בנסיעה רגילה אולם ישים לב למעברי החצייה בלבד.', 'a', '', ARRAY['C1','C','D','A','1','В']),
  ('traffic-laws', 89, 'אתה נוהג בכביש דו-סטרי ומולך יש מבנה, עמוד או שטח סגור. כיצד עליך לנהוג?', 'יש לעבור את המקום מצדו השמאלי.', 'יש לעבור את המקום מצדו הימני, אלא אם כן סומן אחרת.', 'מותר לך לעבור את המקום מצדו הימני או השמאלי.', 'יש להמשיך בנסיעה בהתאם לגודל המבנה או העמוד או השטח הסגור.', 'b', '', ARRAY['C1','C','D','A','1','В']),
  ('traffic-laws', 227, 'האם מותר לנוסעים להיכנס לרכב או לצאת ממנו מן הצד הפונה אל הכביש?', 'אסור, פרט לנוהג בו או פרט לנוסע היושב לצדו כאשר הרכב חונה בשמאל הכביש.', 'מותר, אם אין הדבר מסכן את הנוסעים והנהג.', 'אסור לחלוטין.', 'מותר, אם אין הדבר מפריע לנוסעים.', 'a', '/questions/3227.jpg', ARRAY['C1','C','В']),
  ('traffic-laws', 798, 'על מי חלה האחריות לבטיחות בעת הנסיעה לאחור?', 'על הנוהג ברכב.', 'על בעל הרכב אף על פי שאינו נוהג ברכב באותו הזמן.', 'על האדם המכוון את הנהג בעת הנסיעה לאחור.', 'על כל הנמצאים בקרבת הרכב הנוסע לאחור.', 'a', '', ARRAY['C1','C','D','A','1','В']),
  ('safety', 877, 'מה מחייבת נסיעה אחורנית תמיד?', 'הפעלת זמזם חיצוני לנסיעה לאחור בכל סוגי הרכב, לרבות רכב פרטי.', 'נסיעה בהילוך נמוך בהתאם לתנאי הדרך רק בירידה תלולה.', 'זהירות ונקיטת אמצעים למניעת סיכון, פגיעה, הטרדה או הפרעה.', 'הצבת מכוון במקום שבו ייראה לעיני הנהג.', 'c', '', ARRAY['C1','C','D','1','В']),
