  ('traffic-laws', 70, 'האם לנהג בעל רישיון נהיגה תקף לסוג רכב מסוים מותר לנהוג בכל רכב מאותו סוג?', 'כן, ובתנאי שלא נזקפו לחובתו עבירות תנועה.', 'כן. בעל רישיון נהיגה תקף יכול לנהוג בכל רכב ללא כל תנאי.', 'כן, בתנאי שהנהג בקיא בהפעלתו ובשימוש בו.', 'כן, בתנאי שבידו אישור משטרתי על בקיאות בהפעלת הרכב.', 'c', '', ARRAY['C1','C','D','A','1','В']),
  ('safety', 893, 'נהג מתקרב למעבר חצייה המסומן בכביש. במעבר אין הולכי רגל. לכן על הנהג:', 'להאט ולוודא שאין הולכי רגל קרובים לחצייה.', 'לעבור בזריזות את מעבר החצייה ואין צורך להאט.', 'להאיץ ולחצות לפני שיגיעו הולכי רגל.', 'לצפור ולהאיץ ולעבור במהירות את מעבר החצייה.', 'a', '', ARRAY['C1','C','D','A','1','В']),
