  ('safety', 1531, 'כאשר אתה נוסע מאחורי רכב גדול:', 'שמור על מרחק קטן ביותר מהרכב שלפניך.', 'בעלייה – שמור על מרחק קטן; בירידה – שמור על מרחק כפול.', 'שמור על מרחק גדול יותר מהרכב שלפניך רק כשהוצב תמרור "סכנה כללית".', 'שמור על מרחק גדול מן הרגיל מהרכב הזה, כדי למנוע תאונה.', 'd', '', ARRAY['C1','C','D','A','В']),
  ('vehicle', 742, 'כיצד תבצע הורדת הילוכים בעלייה ברכב בעל תיבת הילוכים אוטומטית, ללא עזרת ידית ההילוכים?', 'בלחיצה הדרגתית על דוושת הדלק, עד לקבלת התוצאה הרצויה.', 'על ידי לחיצה חזקה ומהירה (קיק-דאון) על דוושת הדלק או על ידי הפעלת מתג חשמלי המיועד לכך.', 'בלחיצה חזקה על דוושת הבלם.', 'על ידי הורדת הרגל מדוושת הדלק ללא מתן דלק, לקבלת מהירות רצויה.', 'b', '', ARRAY['C1','C','D','В']),
  ('safety', 781, 'מהו העיקרון החשוב ביותר בפנייה ימינה בצומת?', 'התרחקות משפת הכביש הימנית.', 'להתחיל ולסיים את הפנייה סמוך לשפת הכביש הימנית.', 'לפנות רחוק ככל האפשר מהמדרכה מימין.', 'הכניסה לצומת והיציאה ממנו צריכות להיעשות בקשת רחבה אל מרכז הכביש.', 'b', '', ARRAY['C1','C','D','A','1','В']),
  ('safety', 918, 'בתמונה שלפניך מצולם אירוע. כיצד עליך לנהוג?', 'עבור לנתיב השמאלי ועקוף את הולך הרגל.', 'עצור ליד הולך הרגל והסבר לו כי המקום הנכון להולכי רגל הוא מעבר החצייה הנמצא מאחוריו.', 'עצור לפני הולך הרגל וסמן לו בכל דרך אפשרית על קיומו של מעבר החצייה מאחוריו.', 'האט, היזהר והיכון לעצירה. אל תעשה כל פעולה העלולה לסכן או להבהיל את הולך הרגל.', 'd', '/questions/3917.jpg', ARRAY['C1','C','D','A','1','В']),
  ('traffic-laws', 350, 'כביש חד-סטרי הוא:', 'כביש שבו מותרת התנועה בכיוון אחד בלבד.', 'דרך בת נתיב אחד בלבד.', 'כביש שבכיוון אחד מותר לכל סוגי הרכב לנוע ומנגד – רק לרכב ציבורי.', 'דרך ללא מוצא.', 'a', '', ARRAY['C1','C','D','A','1','В']),
