  ('vehicle', 1035, 'האם מותר להחליף את הצמיגים ברכב לצמיגים בעלי מידה אחרת?', 'בשום מקרה אין לשנות את מידת צמיגי הרכב.', 'מותר לשנות רק באישור מראש של רשות הרישוי במשרד התחבורה.', 'מותר, בתנאי שיוחלפו כל צמיגי הרכב בצמיגים חדשים, שלכולם אותה מידה אחרת, הרצויה לנהג.', 'מותר, אם חברת הביטוח מאשרת את השינוי.', 'b', '', ARRAY['C1','A','В']),
  ('safety', 1529, 'כיצד תנהג רכב בכביש רטוב?', 'לחץ על דוושת המצמד לסירוגין.', 'כמו בכביש יבש. אין הבדל.', 'הגבר מהירות עד לסיום הקטע הרטוב – להגברת הבטיחות.', 'האט ונהג במהירות המתאימה, לפי הנסיבות.', 'd', '', ARRAY['C1','C','D','A','1','В']),
