  ('safety', 924, 'כיצד תנהג על פי הנראה בתמונה?', 'האט והיכון לעצירה. אפשר להולך רגל להשלים את חציית הכביש בבטחה.', 'המשך כרגיל. הולך הרגל זיהה אותך ולכן הוא יעצור ויאפשר לך לעבור בצומת בבטחה.', 'הולך הרגל אינו מבחין בך. אותת לו על ידי צפירה כי אתה ממשיך בנסיעתך.', 'עקוף את הולך הרגל בזהירות לפני שישלים את החצייה.', 'a', '/questions/3924.jpg', ARRAY['C1','C','D','A','1','В']),
  ('signs', 1535, 'איזה תמרור אוסר כניסת הולכי רגל?', '815', '221', '901', '216', 'd', '/signs/sign-216.png', ARRAY['C1','C','D','A','1','В']),
  ('safety', 867, 'מה הם התנאים לנסיעה בקו ישר וללא סטיות?', 'שמירה על ימין הדרך, אגב שמירת רווח קבוע מהפס הצהוב שמימין.', 'התמקדות במטרה הרחוקה ביותר שאליה אפשר להגיע במבט.', 'הפניית מבטים לעבר קו ההפרדה ושמירת רווח קבוע ממנו.', 'מעקב רצוף בעת הנסיעה אחר הפס הצהוב התוחם את הכביש.', 'b', '', ARRAY['C1','C','D','A','1','В']),
  ('traffic-laws', 224, 'האם מותר לנו לנהוג ברכב כשחלק מגופנו מחוץ לרכב?', 'מותר, לנוסעים בוגרים בלבד.', 'מותר, בנסיעה בדרכי עפר.', 'מותר, ברכב אספנות בלבד.', 'אסור, למעט באופנוע.', 'd', '', ARRAY['C1','C','D','В']),
  ('safety', 913, 'מתי יוכלו כלי הרכב שלפניך להמשיך בנסיעתם?', 'תמיד, אחרי שלוש דקות של המתנה.', 'רק כשהמחסום ייפתח כולו ולאחר שהאור האדום ברמזור כבה.', 'מיד עם תחילת פתיחת המחסום.', 'כשהאור ברמזור יתחלף ויהיה בצבע צהוב יציב.', 'b', '/questions/3913.jpg', ARRAY['C1','C','D','A','1','В']),
  ('vehicle', 1033, 'איזו פעולה יש לבצע לאחר החלפת גלגל?', 'לבעוט קלות בצמיג לבדיקה כללית (של תקינות הצמיג ושל כושר הבעיטה).', 'לחזק את אומי (ברגי) הגלגל לאחר הורדת הרכב מן המגבה (ג''ק) ולעשות זאת שוב לאחר נסיעה של 50 ק"מ.', 'לבדוק את חום הצמיג לפני הנסיעה הבאה.', 'אין צורך בשום פעולה מיוחדת.', 'b', '', ARRAY['C1','В']),
  ('safety', 257, 'התחלת עקיפה בכביש דו-סטרי ארוך וישר. באמצע העקיפה ממש מופיע מולך רכב באותו נתיב:', 'הבהב באורות לנהג שממול והשלם את העקיפה כפי שתכננת.', 'האט והפסק את העקיפה וחזור מהר לנתיב הימני.', 'צפור והשלם את העקיפה כרגיל. אתה היית שם לפניו.', 'סטה שמאלה, פנה את הנתיב וסע בשול השמאלי.', 'b', '', ARRAY['C1','C','D','A','1','В']),
  ('safety', 1292, 'כיצד יפעל נוהג ברכב בהתקרבו לקטע כביש שיש עליו שמן?', 'יאט במתינות ככל האפשר ולא יבלום בחזקה.', 'יגביר את מהירות הנסיעה ולא ילחץ על דוושת הבלם.', 'יניע את ההגה ימינה ושמאלה לסירוגין בזמן שהוא נוסע על השמן.', 'ימשיך בנסיעה רגילה, משום שהשמן עוזר להגדלת החיכוך בין הצמיגים ובין הכביש.', 'a', '', ARRAY['C1','C','D','A','1','В']),
  ('traffic-laws', 213, 'האם מותר להעמיד רכב מול תחנת אוטובוס?', 'מותר, בתנאי שרוחב הכביש הוא 12 מטרים או יותר.', 'מותר, רק באור יום ולצורך העלאת נוסעים.', 'אסור בהחלט.', 'מותר, בתנאי שרוחב הכביש 20 מטרים לפחות.', 'a', '', ARRAY['C1','C','D','A','1','В']),
  ('traffic-laws', 69, 'אילו הוראות עדיפות בצומת שבו מוצבים רמזורים ותמרורים?', 'הוראת תמרור "תן זכות קדימה" עדיפה מהוראת רמזור שאינו מהבהב.', 'הוראת תמרור עדיפה תמיד (רמזור עלול להתקלקל).', 'הוראת תמרור "עצור" עדיפה מהוראת רמזור שאינו מהבהב.', 'הוראת רמזור (פרט לאור צהוב מהבהב) עדיפה מהוראת תמרור שמשמעותו מתן זכות קדימה.', 'd', '', ARRAY['C1','C','D','A','1','В']),
  ('signs', 373, 'בכניסה לקטע דרך הוצב תמרור 618. איזה תמרור יופיע בכניסה מצדו האחר של אותו קטע דרך?', '308', '402', '307', '401', 'b', '/signs/sign-618.png', ARRAY['C1','C','D','A','1','В']),
  ('safety', 842, 'כיצד נימנע מהתנגשות חזיתית בנהיגה בדרך הררית צרה ומפותלת?', 'יש לנהוג בהילוך גבוה ולהמעיט בשימוש בבלמים, למניעת אבדן כושר הבלימה של הרכב.', 'יש לנהוג סמוך לקו-האמצע.', 'נאט ונצפור צפירה ארוכה ומתמשכת לפני כל עיקול בדרך.', 'ניסע בימין הקיצוני של הכביש, נדליק אורות ונתאים המהירות לתנאי הדרך.', 'd', '/questions/3839.jpg', ARRAY['C1','C','D','A','1','В']),
  ('traffic-laws', 722, 'כאשר רכב נאלץ לעצור בדרך שאינה עירונית ונהג או נוסע עומד לצאת ממנו:', 'הנהג חייב ללבוש אפוד ביציאתו מן הרכב רק אם יש כלי רכב אחרים בדרך.', 'היוצא ראשון מהרכב חייב ללבוש אפוד זוהר תקני ביציאתו מן הרכב.', 'חובת לבישת אפוד מוטלת על הנהג בלבד, ולא על אדם אחר היוצא מן הרכב.', 'אין חובה כלשהי. חובת לבישת אפוד מוטלת בדרך עירונית בלבד.', 'b', '', ARRAY['C1','C','D','A','1','В']),
  ('traffic-laws', 710, 'כיצד תנהג (רכב 3) בצומת שלפניך?', 'תן זכות קדימה לרוכב האופנוע (1).', 'לך (3) יש זכות קדימה על פני כלי הרכב האחרים.', 'הראשון שמגיע לצומת נכנס לצומת.', 'תן זכות קדימה לרכב האדום (2).', 'a', '/questions/3710.jpg', ARRAY['C1','C','D','A','1','В']),
