  ('traffic-laws', 1686, 'בתום השנתיים של תקופת "נוהג חדש" לא יוענק רישיון נהיגה רגיל ל"נוהג חדש" שהורשע בעבירת:', 'נסיעה ברכב מנועי ללא ביטוח תקף.', 'נהיגה ברכב מנועי בהשפעת אלכוהול או סמים משכרים.', 'אי עצירה בצומת שהוצב בו תמרור "עצור".', 'אי הצבת משולש אזהרה בעת שהרכב הועמד בדרך בשל קלקול.', 'b', '', ARRAY['C1','A','1','В']),
  ('safety', 312, '"שתיית אלכוהול משבשת בפועל את יכולת השיפוט, והנהג מרשה לעצמו להסתכן יותר". נכון או לא?', 'נכון.', 'לא נכון. אלכוהול משפר את יכולת הנהיגה.', 'לעתים רחוקות זה נכון.', 'נכון לעיתים.', 'a', '', ARRAY['C1','C','D','A','1','В']),
