  ('traffic-laws', 159, 'כיצד עליך לנהוג כשמוצב תמרור "עצור" לפני מפגש מסילת ברזל?', 'עצור כנהוג בכל מקום שבו מוצב תמרור "עצור", והמשך בנסיעה.', 'חובה עליך לעצור רק אם רכבת מתקרבת, נראית או נשמעת.', 'בלילה חובה לעצור. ביום – לא.', 'עצור את רכבך, כבה את מקלט הרדיו או הטלוויזיה או את הקלטת ופתח את חלון הרכב הקרוב אליך.', 'd', '', ARRAY['C1','C','A','В']),
  ('signs', 672, 'כיצד תנהג כשהאור הצהוב ברמזור מהבהב?', 'התקדם בזהירות ואפשר להולך רגל לחצות בבטחה את הכביש.', 'עצור ואל תמשיך בנסיעה עד שיכבה האור הצהוב המהבהב ברמזור.', 'התעלם ממנו. הוא מכוון להולכי רגל בלבד.', 'עצור תמיד לפני מעבר חצייה, גם אם אין איש במעבר.', 'a', '/questions/3672.jpg', ARRAY['C1','C','D','A','1','В']),
  ('safety', 827, 'כיצד תסב את תשומת לבו של נהג הרכב הנעקף כשאתה עוקף אותו, בדרך  שאינה עירונית?', 'מותר לך לצפור קלות לפני המעבר על פניו, אם הדבר נחוץ.', 'הדלק את פנסי החנייה של הרכב באור יום, אם הדבר נחוץ.', 'סמן לו בעזרת ארבעת מחווני הכיוון של הרכב, אם הדבר נחוץ.', 'צפור במשך כל זמן המעבר על פניו. חשוב שלא יתעלם ממך.', 'a', '', ARRAY['C1','C','D','A','1','В']),
