  ('signs', 460, 'כיצד יש לנהוג ממקום הצבת התמרור ועד אחרי המסילה?', 'לעצור ולהמתין להוראות של אתת/דגלן.', 'להאט, לבדוק ולוודא שאפשר לעבור את המסילות בנסיעה רצופה וללא עיכוב. אל תעצור על המסילות.', 'להאט ולעצור לפני המסילה עד שהרכבת עברה.', 'עבור את המסילה במהירות.', 'b', '/questions/3459.jpg', ARRAY['C1','C','D','A','1','В']),
  ('safety', 1550, 'נהג המרגיש עייפות בלילה צריך:', 'לחפש מקום בטוח למנוחה ולתנומה קלה באופן שלא יפריע לתנועה.', 'לאכול ארוחה דשנה ולהימנע משתייה.', 'להאזין לרדיו, אך לא למוסיקה מרגיעה.', 'לפתוח את החלון שלצדו, לזרימת אוויר.', 'a', '', ARRAY['C1','C','D','В']),
  ('vehicle', 765, '"שמירת רווח מהרכב שלפניך בעת הנהיגה משפיעה על צריכת הדלק ועל הבלאי של הרכב". נכון או לא?', 'לא נכון. שמירת רווח מתאים מהרכב שלפניך גורמת לשחיקת בלמים.', 'נכון. שמירת רווח תמנע שחיקת בלמים וצריכת דלק מופרזת, הנובעות מהאצות ומבלימות תכופות.', 'לא נכון. ויסות הרווח על ידי שימוש בבלמים ובדוושת הדלק חשוב להגברת הערנות של הנהג.', 'לא נכון. לרווח אין השפעה על בלאי הרכב או על תצרוכת הדלק.', 'b', '', ARRAY['C1','C','D','A','1','В']),
  ('safety', 779, 'מהי הפעולה הראשונה שמבצעים נהגים בסדר הפעולות לחציית צמתים?', 'מסתכלים מעבר לצומת, כדי לזהות את נתיבי הכניסה לכיוונים הנגדיים ואת התנועה בהם.', 'בודקים ומזהים את הנתיבים לאחר המעבר בצומת, בעיקר בכיוון שאליו הם נוסעים.', 'נכנסים לצומת.', 'מוודאים שהצומת פנוי ושניתן להשלים את המעבר בצומת בבטחה.', 'd', '', ARRAY['C1','C','D','A','1','В']),
  ('traffic-laws', 1641, 'אם ברישיון הנהיגה רשומות הגבלות:', 'הן נוגעות לתקן האופנוע ולא לאופן הרכיבה עליו.', 'נהג הרכב יפעיל את שיקול דעתו כיצד לפעול ולאיזו מגבלה להתייחס.', 'ההגבלה היא המלצה ואין היא מחייבת את נהג הרכב.', 'נהג הרכב חייב לנהוג בהתאם להגבלות הרשומות.', 'd', '', ARRAY['C1','C','D','A','1','В']),
  ('signs', 512, 'מה פירוש התמרורים?', 'בלילה אסור לנסוע במהירות הגבוהה מ-60  קמ"ש; ביום –  מותר.', 'הגבלת משקל – 60 טונות.', 'מהירות מיוחדת: בזמן ערפל או אובך אסור לנסוע מהר יותר מן הרשום.', 'מהירות מיוחדת: אסור לנסוע מהר יותר מהרשום בתמרור (בקמ"ש).', 'd', '/questions/3512.jpg', ARRAY['C1','C','D','A','1','В']),
  ('traffic-laws', 307, 'האם מותר לנהג לסרב להיבדק בדיקת שכרות לפי דרישת שוטר?', 'מותר לסרב, מפני שהשוטר מייצג את מערכת הבריאות ולא את החוק.', 'מותר לסרב להיבדק, בגלל חוק צנעת הפרט.', 'לנהג אסור לסרב לדרישתו של שוטר להיבדק בדיקת נשיפה או למסור דגימה של דם או שתן או רוק לבדיקה.', 'מותר לסרב להיבדק משום שהבדיקה נוגדת את חוק יסוד זכויות האדם וחירותו.', 'c', '', ARRAY['C1','C','D','A','1','В']),
  ('signs', 524, 'תוקפו של התמרור עד:', 'לתמרור המתיר נסיעה במהירות מוגבלת.', 'לצומת המרומזר הקרוב בלבד.', 'לצומת הקרוב או עד לתמרור המורה על ביטולו או עד לתמרור "חנייה לכלי רכב".', 'לתמרור המציין דרך שאינה עירונית.', 'c', '/questions/3524.jpg', ARRAY['C1','C','D','A','1','В']),
  ('traffic-laws', 709, 'כיצד תנהג (רכב 3) בצומת שלפניך?', 'תן זכות קדימה לרוכב האופנוע (2) ולאוטובוס הצהוב (1).', 'סע קדימה בזהירות. נהגי כלי הרכב (1, 2 ) חייבים לתת לך זכות קדימה.', 'תן זכות קדימה לאופנוע בלבד (2).', 'תן זכות קדימה לאוטובוס הצהוב בלבד (1).', 'a', '/questions/3709.jpg', ARRAY['C1','C','D','A','1','В']),
  ('traffic-laws', 341, 'באילו תנאים תאשר רשות הרישוי רישום שינוי בעלות על רכב?', 'לאחר שהתקבל אישור מרשם המשכונות כי הרכב נקי מכל עיקול או שעבוד בלבד.', 'לאחר שרוכש הרכב שילם את האגרה הקבועה בחוק, כולל ארנונה על מקום החנייה.', 'לאחר שהוכח לרשות כי שולמו כל האגרות והמסים והוסר מהרכב כל עיקול או שעבוד ואין הגבלה אחרת.', 'לאחר שהמוכר שילם והציג אישור מרשם המשכונות.', 'c', '', ARRAY['C1','C','D','A','1','В']),
  ('safety', 852, 'כיצד תנהג בלילה כשהרכב הבא מולך מסנוור אותך?', 'האט, היצמד לימין והבט על הקו הצהוב או על שפת הכביש הימנית.', 'עצור בימין הדרך והפעל את אורות החנייה עד שיחלוף הרכב הבא ממול.', 'הפעל את האור הגבוה כדי לשפר את שדה ראייתך.', 'צפור בחזקה כדי להתריע בפני הנהג ממול כי הוא מסנוור אותך.', 'a', '', ARRAY['C1','C','D','A','1','В']),
  ('traffic-laws', 284, 'מה עליך לעשות אם רכבך משמיע רעש בלתי סביר?', 'מותר לנהוג ברכב המשמיע רעש בלתי סביר - בדרך שאינה עירונית.', 'מותר לנהוג ברכב המשמיע רעש בלתי סביר ללא הגבלה.', 'אין לנהוג ברכב המשמיע רעש בלתי סביר.', 'מותר לנהוג ברכב המשמיע רעש בלתי סביר - באישור הרשות המקומית.', 'c', '', ARRAY['C1','C','D','A','1','В']),
