  ('traffic-laws', 30, 'מיהו "עובר דרך"?', 'המשתמש בכביש לרכיבה על אופניים בלבד.', 'המשתמש בדרך לנסיעה ברכב מנועי בלבד.', 'המשתמש בדרך לעמידה או לריצה בלבד.', 'המשתמש בדרך לנסיעה, להליכה, לעמידה או לכל מטרה אחרת.', 'd', '', ARRAY['C1','C','D','A','1','В']),
  ('traffic-laws', 303, '"החוק אינו אוסר נהיגה תחת השפעת סמים משכרים (אסורים)":', 'לא נכון. החוק מציין במפורש איסור נהיגה בהשפעת כמות מסוימת של סמים משכרים בדם.', 'נכון. החוק אוסר רק נהיגה בהשפעת אלכוהול.', 'לא נכון. החוק אוסר במפורש נהיגה בהשפעת סמים משכרים.', 'נכון, מאחר ששימוש בסמים משכרים אינו אסור בחוק.', 'c', '', ARRAY['C1','C','D','A','1','В']),
  ('traffic-laws', 131, 'האם מותר לעקוף או לנסות לעקוף רכב אחר בתחום של 100 מטרים לפני מסילת ברזל?', 'מותר, בתנאי שרכבת אינה נראית ואינה נשמעת.', 'מותר, אם הנעקף הוא אופנוע.', 'אסור בהחלט.', 'מותר, אם הרכב הנעקף הוא טרקטור.', 'c', '', ARRAY['C1','C','D','A','1','В']),
